for (let i = 0; i < 6; i++) {
  if (i % 2 === 0) {
    continue;
  }
  console.log(i);
}

for i in range(6):
  if i % 2 == 0:
    continue
  print(i)

for (int i = 0; i < 6; i++) {
  if (i % 2 == 0) continue;
  System.out.println(i);
}

DECLARE @i INT = 0;
WHILE @i < 6
BEGIN
  IF @i % 2 = 0
    BEGIN
      SET @i = @i + 1;
      CONTINUE;
    END
  SET @i = @i + 1;
END;
